INSERT INTO `blog_cauhinh` VALUES ('Võ Lâm Hồi Ức Mobile', 'Phiên bản CTC 2005 chính thức trở lại, cùng trải nghiệm quá khứ Võ Lâm hào hùng của năm 2005 như PK, săn boss Hoàng Kim, Công Thành Chiến, Liên Đấu, Vượt Ải...', 'võ lâm truyền kỳ, vltk, công thành chiến, võ lâm miễn phí, võ lâm, võ lâm free, võ lâm lậu, vo lam truyen ky, cong thanh chien, vo lam mien phi, vo lam, vo lam lau, vo lam free, vo lam private, võ lâm private', 'https://jx1hoiuc.mobi/huong-dan-tai-va-cai-dat-game.html', 'https://testflight.apple.com/join/TKPYhaQ8', 'https://id.jx1hoiuc.mobi/												', 'https://id.jx1hoiuc.mobi/', 'https://www.facebook.com/vlcotruyen', 'https://www.facebook.com/groups/vlcotruyen', 'Thông báo khai mở máy chủ công thành chiến test vĩnh viễn miện phí 100%', '999 999 999', 'static/assets/imgs/600x315.jpg', 'https://jx1hoiuc.mobi/', 'https://jx1hoiuc.mobi/huong-dan-nap-kim-nguyen-bao.html', 'https://jx1hoiuc.mobi/', 'https://jx1hoiuc.mobi/');

