-- ----------------------------
-- Records of blog_posts_seo
-- ----------------------------
INSERT INTO `blog_posts_seo` VALUES (25, 'Hệ Thống Ngũ Hành', 'he-thong-ngu-hanh', NULL, '<p>Trong Triết Học cổ Trung Hoa, tất cả vạn vật đều ph&aacute;t sinh từ 5 nguy&ecirc;n tố cơ bản v&agrave; phải lu&ocirc;n lu&ocirc;n trải qua năm trạng th&aacute;i được gọi l&agrave;:&nbsp;<strong>Mộc, Hỏa, Thổ, Kim v&agrave; Thủy.</strong>&nbsp;Năm trạng th&aacute;i n&agrave;y gọi l&agrave; Ngũ h&agrave;nh. Ngũ h&agrave;nh ch&iacute;nh l&agrave; sự tương t&aacute;c v&agrave; quan hệ của vạn vật.</p>\r\n\r\n<p>Điểm đặc sắc v&agrave; th&uacute; vị nhất m&agrave; V&otilde; L&acirc;m Truyền Kỳ đem đến cho người chơi đ&oacute; l&agrave; &aacute;p dụng&nbsp;<strong>nguy&ecirc;n tắc Ngũ h&agrave;nh</strong>&nbsp;v&agrave;o việc chọn lựa m&ocirc;n ph&aacute;i, quần &aacute;o, vũ kh&iacute;,&hellip; B&iacute; ẩn lu&ocirc;n tạo n&ecirc;n sự hấp dẫn. V&agrave; tất cả đang chờ đ&oacute;n đồng đạo gần xa c&ugrave;ng kh&aacute;m ph&aacute;.</p>\r\n\r\n<p>Tồn tại trong Ngũ h&agrave;nh c&oacute; hai nguy&ecirc;n l&yacute; cơ bản: Tương Sinh v&agrave; Tương Khắc.</p>\r\n\r\n<h4>Ngũ h&agrave;nh tương sinh</h4>\r\n\r\n<p>Mộc sinh Hỏa sinh Thổ sinh Kim sinh Thủy sinh Mộc</p>\r\n\r\n<ul>\r\n	<li>Tương Sinh l&agrave; mối quan hệ hỗ trợ lẫn nhau, gi&uacute;p đỡ nhau c&ugrave;ng ph&aacute;t triển. Trong luật tương sinh của ngũ h&agrave;nh c&ograve;n bao h&agrave;m &yacute; nữa l&agrave; h&agrave;nh n&agrave;o cũng c&oacute; quan hệ tr&ecirc;n hai phương diện:&nbsp;<strong>c&aacute;i sinh ra n&oacute; v&agrave; c&aacute;i n&oacute; sinh ra.</strong></li>\r\n	<li>Điểm đặc sắc v&agrave; th&uacute; vị nhất m&agrave; V&otilde; L&acirc;m Truyền Kỳ đem đến cho người chơi đ&oacute; l&agrave; &aacute;p dụng nguy&ecirc;n tắc&nbsp;<strong>Ngũ h&agrave;nh</strong>&nbsp;v&agrave;o việc chọn lựa m&ocirc;n ph&aacute;i, quần &aacute;o, vũ kh&iacute;,&hellip; B&iacute; ẩn lu&ocirc;n tạo n&ecirc;n sự hấp dẫn. V&agrave; tất cả đang chờ đ&oacute;n đồng đạo gần xa c&ugrave;ng kh&aacute;m ph&aacute;.</li>\r\n</ul>\r\n\r\n<h4>Ngũ h&agrave;nh tương khắc</h4>\r\n\r\n<p>Mộc khắc Thổ khắc Thủy khắc Hỏa khắc Kim khắc Mộc</p>\r\n\r\n<ul>\r\n	<li>Tương khắc c&oacute; nghĩa l&agrave;&nbsp;<strong>&aacute;p chế</strong>&nbsp;lẫn nhau. Trong tương khắc, mỗi h&agrave;nh cũng lại c&oacute; hai mối quan hệ:&nbsp;<strong>c&aacute;i khắc n&oacute; v&agrave; c&aacute;i n&oacute; khắc.</strong></li>\r\n	<li>Hiện tượng tương sinh, tương khắc kh&ocirc;ng tồn tại độc lập với nhau.&nbsp;<strong>Trong tương khắc đ&atilde; c&oacute; mầm mống của tương sinh, trong tương sinh đ&atilde; c&oacute; mầm mống của tương khắc.</strong>&nbsp;Do đ&oacute; vạn vật lu&ocirc;n lu&ocirc;n tồn tại v&agrave; ph&aacute;t triển.</li>\r\n</ul>\r\n\r\n<h4>Ngũ h&agrave;nh &amp; Thập đại m&ocirc;n ph&aacute;i</h4>\r\n\r\n<table align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\r\n	<thead>\r\n		<tr>\r\n			<th>Hệ Kim</th>\r\n			<th>Đồng đạo c&oacute; thể chọn m&ocirc;n ph&aacute;i Thiếu L&acirc;m thuộc ch&iacute;nh ph&aacute;i v&agrave; Thi&ecirc;n Vương Bang ở vị tr&iacute; trung lập.</th>\r\n		</tr>\r\n	</thead>\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"vertical-align:middle\">Hệ Mộc</td>\r\n			<td style=\"vertical-align:middle\">\r\n			<ul>\r\n				<li>Người chơi c&oacute; thể gia nhập ph&aacute;i Đường M&ocirc;n ph&iacute;a Trung Lập v&agrave; Ngũ Độc Gi&aacute;o ph&iacute;a t&agrave; ph&aacute;i.</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:middle\">Hệ Thổ</td>\r\n			<td style=\"vertical-align:middle\">\r\n			<ul>\r\n				<li>Người chơi c&oacute; thể gia nhập V&otilde; Đang ch&iacute;nh ph&aacute;i v&agrave; C&ocirc;n Lu&acirc;n trung lập.</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:middle\">Hệ Thuỷ</td>\r\n			<td style=\"vertical-align:middle\">\r\n			<ul>\r\n				<li>Chỉ để cho nữ giới lựa chọn, đ&oacute; c&oacute; thể l&agrave; ph&aacute;i Nga My ch&iacute;nh ph&aacute;i hoặc ph&aacute;i Th&uacute;y Y&ecirc;n trung lập.</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:middle\">Hệ Hoả</td>\r\n			<td style=\"vertical-align:middle\">\r\n			<ul>\r\n				<li>C&oacute; C&aacute;i Bang ch&iacute;nh ph&aacute;i v&agrave; Thi&ecirc;n Nhẫn t&agrave; ph&aacute;i</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<h4>Ngũ h&agrave;nh tương khắc đối với c&aacute;c m&ocirc;n ph&aacute;i</h4>\r\n\r\n<p>Mộc khắc Thổ khắc Thủy khắc Hỏa khắc Kim khắc</p>\r\n\r\n<ul>\r\n	<li>Mỗi nh&acirc;n vật bạn chọn sẽ tương ứng với một thuộc t&iacute;nh Ngũ h&agrave;nh. Chỉ&nbsp;<strong>khi đạt cấp 10,</strong>&nbsp;th&igrave; người chơi mới c&oacute; thể&nbsp;<strong>chọn cho m&igrave;nh một m&ocirc;n ph&aacute;i cố định.</strong>&nbsp;V&agrave; quan hệ tương khắc Ngũ h&agrave;nh ảnh hưởng s&acirc;u sắc tới thuộc t&iacute;nh nh&acirc;n vật người chơi.</li>\r\n	<li><strong>V&igrave; Hỏa khắc Kim n&ecirc;n:</strong>&nbsp;Ngay khi sinh ra người h&agrave;nh&nbsp;<strong>Kim</strong>&nbsp;c&oacute; chỉ số kh&aacute;ng hỏa thấp, nghĩa l&agrave; người hệ&nbsp;<strong>Kim</strong>&nbsp;rất sợ v&otilde; c&ocirc;ng hay qu&aacute;i vật h&agrave;nh&nbsp;<strong>Hỏa</strong></li>\r\n	<li>Cứ thế, nếu bạn chọn người h&agrave;nh Hỏa th&igrave; khi gặp qu&aacute;i vật hay v&otilde; c&ocirc;ng h&agrave;nh Thủy sẽ giảm khả năng tự vệ của ch&iacute;nh m&igrave;nh.</li>\r\n</ul>\r\n\r\n<h4>Nguy&ecirc;n tắc trang bị</h4>\r\n\r\n<p><strong>T</strong>huộc t&iacute;nh Ngũ h&agrave;nh được &aacute;p dụng trong c&aacute;ch trang bị quần &aacute;o, vũ kh&iacute;, nhẫn, n&oacute;n&hellip; tạo n&ecirc;n một sức hấp dẫn lạ kỳ đối với người chơi V&otilde; L&acirc;m Truyền Kỳ. Kh&ocirc;ng phải c&oacute; g&igrave; mặc đ&oacute; m&agrave; phải mặc sao cho tốt v&agrave; hiệu quả, phải lựa chọn v&agrave; hiểu được tương sinh Ngũ h&agrave;nh trong từng trang bị để k&iacute;ch hoạt tối đa sức mạnh của trang bị đ&oacute;.</p>\r\n\r\n<p>Mỗi nh&acirc;n vật bạn chọn sẽ c&oacute;&nbsp;<strong>10 loại trang thiết bị.</strong>&nbsp;Mỗi thiết bị đều c&oacute; thuộc t&iacute;nh Ngũ h&agrave;nh (Mộc &ndash; Hỏa &ndash; Thổ - Kim &ndash; Thủy) v&agrave; thuộc t&iacute;nh ẩn (hiển thị chữ m&agrave;u x&aacute;m). Để khai th&aacute;c tối đa hiệu quả c&aacute;c loại trang bị, người chơi cần t&igrave;m hiểu v&agrave; mặc đ&uacute;ng nguy&ecirc;n tắc Ngũ h&agrave;nh để ch&uacute;ng hỗ trợ, k&iacute;ch hoạt c&aacute;c thuộc t&iacute;nh ẩn của nhau.</p>\r\n\r\n<p>10 loại trang bị được chia l&agrave;m 5 cặp ch&iacute;nh, hỗ trợ - k&iacute;ch hoạt thuộc t&iacute;nh &acirc;m của nhau.</p>\r\n\r\n<table align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"vertical-align:middle\">Cặp 1</td>\r\n			<td style=\"vertical-align:middle\">Trang phục &ndash; D&acirc;y chuyền</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:middle\">Cặp 2</td>\r\n			<td style=\"vertical-align:middle\">Mũ &ndash; Vũ kh&iacute;</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:middle\">Cặp 3</td>\r\n			<td style=\"vertical-align:middle\">Gi&agrave;y &ndash; Nhẫn tr&aacute;i (tr&ecirc;n)</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:middle\">Cặp 4</td>\r\n			<td style=\"vertical-align:middle\">Bao tay &ndash; Ngọc Bội</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:middle\">Cặp 5</td>\r\n			<td style=\"vertical-align:middle\">Thắt lưng &ndash; Nhẫn tr&aacute;i (dưới)</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<ul>\r\n	<li>(Cặp 1) hỗ trợ (Cặp 2) hỗ trợ (Cặp 3) hỗ trợ (Cặp 4) hỗ trợ (Cặp 5)</li>\r\n	<li><strong>V&iacute; dụ:</strong></li>\r\n</ul>\r\n\r\n<p><img src=\"https://img.zing.vn/volam/images/tailieuthamkhao/nguhanh/ngu_hanh_sinhkhac.gif\" style=\"height:327px; width:358px\" /></p>\r\n\r\n<ul>\r\n	<li><strong>Trang phục</strong>&nbsp;c&oacute; thể k&iacute;ch hoạt thuộc t&iacute;nh &acirc;m của&nbsp;<strong>Vũ kh&iacute; v&agrave; Mũ.</strong></li>\r\n	<li><strong>D&acirc;y chuyền</strong>&nbsp;cũng c&oacute; thể k&iacute;ch hoạt thuộc t&iacute;nh &acirc;m của&nbsp;<strong>Vũ kh&iacute; v&agrave; Mũ.</strong></li>\r\n	<li><strong>Vũ kh&iacute;</strong>&nbsp;c&oacute; thể k&iacute;ch hoạt thuộc t&iacute;nh &acirc;m của&nbsp;<strong>Gi&agrave;y v&agrave; Nhẫn</strong>&nbsp;tr&ecirc;n.</li>\r\n	<li>Cứ như vậy, một trang bị c&oacute; thể k&iacute;ch hoạt thuộc t&iacute;nh &acirc;m của 2 trang bị kh&aacute;c.</li>\r\n</ul>\r\n\r\n<p><img src=\"https://img.zing.vn/volam/images/tailieuthamkhao/nguhanh/trangbithuoctinh.jpg\" style=\"width:500px\" /></p>\r\n\r\n<ul>\r\n	<li>D&ograve;ng c&oacute; m&agrave;u xanh dương l&agrave; thuộc t&iacute;nh đ&atilde; được k&iacute;ch hoạt\r\n	<ul>\r\n		<li>Sinh lực tối đa: th&ecirc;m v&agrave;o 62 Điểm</li>\r\n		<li>Thời gian phục hồi: giảm bới 30.</li>\r\n	</ul>\r\n	</li>\r\n	<li>D&ograve;ng c&oacute; m&agrave;u x&aacute;m l&agrave; thuộc t&iacute;nh &acirc;m chưa được k&iacute;ch hoạt\r\n	<ul>\r\n		<li>Kh&aacute;ng băng: th&ecirc;m v&agrave;o 23%</li>\r\n	</ul>\r\n	</li>\r\n	<li>D&ograve;ng m&agrave;u v&agrave;ng l&agrave; hướng dẫn để k&iacute;ch hoạt thuộc t&iacute;nh &acirc;m\r\n	<ul>\r\n		<li>Cần hệ Hỏa của Nhẫn b&ecirc;n tay tr&aacute;i (dưới) v&agrave; Thắt lưng để k&iacute;ch th&iacute;ch thuộc t&iacute;nh &acirc;m.</li>\r\n	</ul>\r\n	</li>\r\n	<li>Chỉ khi trang bị đ&uacute;ng&nbsp;<strong>Nhẫn b&ecirc;n tay tr&aacute;i dưới v&agrave; thắt lưng hệ Hỏa</strong>&nbsp;th&igrave; thuộc t&iacute;nh &acirc;m của&nbsp;<strong>Tr&iacute;ch Lịch Kim Phong gi&aacute;p</strong>&nbsp;mới được k&iacute;ch hoạt.</li>\r\n	<li>Tương tự như thế, một số trang bị kh&aacute;c cũng c&oacute; một số thuộc t&iacute;nh ẩn cần được k&iacute;ch hoạt để ph&aacute;t huy tối đa hiệu quả của n&oacute;.</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n', '2021-09-22 20:33:10', NULL, 'https://i0.wp.com/s1.uphinh.org/2021/09/23/menh-thuy-hop-mau-gi-ky-mau-nao-e1585539507471.jpg');
INSERT INTO `blog_posts_seo` VALUES (26, 'Hướng Dẫn Tải Và Cài Đặt Game', 'huong-dan-tai-va-cai-dat-game', NULL, '<p style=\"text-align:center\">&nbsp;</p>\r\n\r\n<table align=\"center\" border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:500px\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"text-align:center\"><span style=\"color:#e67e22\"><span style=\"font-size:16px\"><strong>Tải APK trực tiếp</strong></span></span></td>\r\n			<td style=\"text-align:center\"><span style=\"color:#e67e22\"><span style=\"font-size:16px\"><strong>Tải Tr&ecirc;n CH Play</strong></span></span></td>\r\n			<td style=\"text-align:center\"><span style=\"font-size:16px\"><span style=\"color:#16a085\"><strong>Tải Game IOS</strong></span></span></td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n			<p style=\"text-align:center\"><a href=\"https://drive.google.com/file/d/1RJJEriLrdzP1z1-pBC3QgsMNwCsf9bEk/view?usp=sharing\" target=\"_blank\"><img alt=\"Download\" src=\"https://jx1hoiuc.mobi/static/assets/imgs/googleplay.png\" style=\"height:80px; width:251px\" /></a></p>\r\n			</td>\r\n			<td>\r\n			<p style=\"text-align:center\"><a href=\"https://play.google.com/store/apps/details?id=com.thuong.volam&amp;hl=vi\" target=\"_blank\"><img alt=\"Download\" src=\"https://jx1hoiuc.mobi/static/assets/imgs/googleplay.png\" style=\"height:80px; width:251px\" /></a></p>\r\n			</td>\r\n			<td style=\"text-align:center\"><a href=\"https://testflight.apple.com/join/TKPYhaQ8\" target=\"_blank\"><img alt=\"Download\" src=\"https://jx1hoiuc.mobi/static/assets/imgs/appstore.png\" style=\"height:83px; width:213px\" /></a></td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p style=\"text-align:center\">Sau khi tải xong, h&atilde;y c&agrave;i đặt game</p>\r\n\r\n<h2>Bạn chỉ cần&nbsp;tải bản cập nhật&nbsp;ở b&ecirc;n dưới, sau đ&oacute; tiến h&agrave;nh l&agrave;m theo hướng dẫn.&nbsp;</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p><strong>Bước 1</strong>: Tải 1 trong c&aacute;c đường dẫn ở tr&ecirc;n về điện thoại</p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Bước 2</strong>: Cập nhật l&ecirc;n phi&ecirc;n bản mới nhất của JX1 HỒI ỨC MOBILE m&agrave; bạn đang c&oacute;</p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Bước 3</strong>: Thiết Bị IPHONE H&atilde;y Tải V&agrave; C&agrave;i Đặt Ứng Dụng Testfight về trước - Rồi ấn v&agrave;o đường link APP STORE Tải - &gt; Mở Lại Ứng Dụng Testfight Để C&agrave;i Đặt Game&nbsp;</p>\r\n	</li>\r\n	<li><strong>Bước 4</strong>: H&atilde;y Sử Dụng Mạng Với Đường Truyền Ổn Định Để C&agrave;i Đặt Game Được Nhanh Hơn&nbsp;</li>\r\n</ul>\r\n\r\n<p><strong>Nếu kh&ocirc;ng thể khởi động game, h&atilde;y thử 2 c&aacute;ch sau:</strong></p>\r\n\r\n<ul><br />\r\n	<li>Li&ecirc;n hệ Fanpage để được c&aacute;c kỹ thuật vi&ecirc;n gi&uacute;p đỡ</li>\r\n</ul>\r\n', '2021-09-23 15:41:53', NULL, 'https://nkvs2.gosu.vn/public/static/uploads/new/2021/6/dai-hoi-vo-lam/331x175.jpg');
INSERT INTO `blog_posts_seo` VALUES (30, 'TRUNG GIAN GIAO DỊCH', 'trung-gian-giao-dich', NULL, '<p><strong>C&Aacute;C BƯỚC GIAO DỊCH T&Agrave;I KHOẢN:</strong></p>\r\n\r\n<ul>\r\n	<li>&nbsp;Bước 1: B&ecirc;n b&aacute;n v&agrave; mua thỏa thuận rồi li&ecirc;n lạc hotline</li>\r\n	<li>&nbsp;Bước 2: Người mua: chuyển tiền v&agrave;o số t&agrave;i khoản ở tr&ecirc;n</li>\r\n	<li>&nbsp;Bước 3: Người b&aacute;n: chuyển số điện thoại của account sang ....</li>\r\n	<li>&nbsp;Bước 4: GM: chuyển số điện thoại cho người mua, v&agrave; chuyển tiền cho người b&aacute;n</li>\r\n	<li>&nbsp;Kết th&uacute;c giao dịch</li>\r\n</ul>\r\n\r\n<p><strong>C&Aacute;C BƯỚC GIAO DỊCH XU/VẬT PHẨM:</strong></p>\r\n\r\n<ul>\r\n	<li>&nbsp;Bước 1: B&ecirc;n b&aacute;n v&agrave; mua thỏa thuận rồi li&ecirc;n lạc hotline</li>\r\n	<li>&nbsp;Bước 2: Người mua: chuyển tiền v&agrave;o số t&agrave;i khoản ở tr&ecirc;n</li>\r\n	<li>&nbsp;Bước 3: Người b&aacute;n: giao dịch vật phẩm cho GM</li>\r\n	<li>&nbsp;Bước 4: GM: giao vật phẩm sang người mua, v&agrave; chuyển tiền cho người b&aacute;n</li>\r\n	<li>&nbsp;Kết th&uacute;c giao dịch</li>\r\n</ul>\r\n\r\n<p><strong>ĐỔI T&Ecirc;N ĐĂNG NHẬP:</strong></p>\r\n\r\n<ul>\r\n	<li>&nbsp;<strong>Lệ ph&iacute;:</strong>&nbsp;100k/t&agrave;i khoản</li>\r\n	<li>&nbsp;<strong>T&aacute;c dụng:&nbsp;</strong>Chuyển nh&acirc;n vật từ t&agrave;i khoản cũ sang t&agrave;i khoản mới</li>\r\n	<li>&nbsp;Bước 1: Chủ t&agrave;i khoản chuyển số điện thoại của account sang v&agrave; cung cấp t&agrave;i khoản mới</li>\r\n	<li>&nbsp;Bước 2: GM&nbsp;sẽ kiểm tra v&agrave; chuyển nh&acirc;n vật sang t&agrave;i khoản mới</li>\r\n	<li>&nbsp;Kết th&uacute;c thao t&aacute;c</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>QUY ĐỊNH:</strong></p>\r\n\r\n<ul>\r\n	<li>&nbsp;Nhằm tr&aacute;nh c&aacute;c trường hợp lừa đảo hoặc lợi dụng giao dịch để tẩu t&aacute;n đồ hack, cũng như để bảo vệ t&agrave;i sản cho người chơi, JX1 HỒI ỨC MOBILE&nbsp;nghi&ecirc;m cấm người chơi sử dụng c&aacute;c h&igrave;nh thức giao dịch th&ocirc;ng qua người kh&aacute;c. Nếu ph&aacute;t hiện ch&uacute;ng t&ocirc;i sẽ xử l&yacute; mạnh tay với c&aacute;c ID nhận giao dịch v&agrave; cả ID giới thiệu giao dịch.</li>\r\n	<li>&nbsp;C&aacute;c giao dịch kh&ocirc;ng th&ocirc;ng qua bộ phận trung gian của JX1 HỒI ỨC MOBILE&nbsp;sẽ kh&ocirc;ng được c&ocirc;ng nhận v&agrave; kh&ocirc;ng được bảo vệ. Trong trường hợp c&aacute;c account hoặc vật phẩm đ&oacute; l&agrave; đồ hack th&igrave; sẽ bị thu hồi</li>\r\n	<li>&nbsp;Mong c&aacute;c bang chủ t&ocirc;n trọng ch&uacute;ng t&ocirc;i v&agrave; kh&ocirc;ng đứng ra l&agrave;m trung gian cho c&aacute;c th&agrave;nh vi&ecirc;n trong bang hoặc người quen! V&igrave; sẽ c&oacute; l&uacute;c c&oacute; người kh&aacute;c lợi dụng việc đ&oacute; rồi giả danh để lừa đảo, g&acirc;y mất đo&agrave;n kết nội bộ, mất uy t&iacute;n cho bang chủ v&agrave; ảnh hưởng đến sự ph&aacute;t triển của game.</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>LƯU &Yacute;:</strong></p>\r\n\r\n<ul>\r\n	<li>&nbsp;JX1 HỒI ỨC MOBILE &nbsp;chỉ sử dụng duy nhất 1 t&agrave;i khoản Facebook ở tr&ecirc;n để thực hiện việc trung gian giao dịch. Cần cảnh gi&aacute;c với những người giả mạo t&ecirc;n Facebook để lừa đảo</li>\r\n	<li>&nbsp;JX1 HỒI ỨC MOBILE&nbsp;chỉ sử dụng duy nhất 1 số t&agrave;i khoản ở tr&ecirc;n để thực hiện trung gian, kh&ocirc;ng sử dụng t&agrave;i khoản kh&aacute;c hoặc t&ecirc;n chủ t&agrave;i khoản n&agrave;o kh&aacute;c.&nbsp;</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n', '2022-01-14 17:17:52', NULL, 'st/mainsite/imgs/no-image-2.jpg');
INSERT INTO `blog_posts_seo` VALUES (27, 'Hái quả huy hoàng', 'hai-qua-huy-hoang', NULL, '<p><strong>Hạt Huy Ho&agrave;ng</strong>&nbsp;v&agrave;&nbsp;<strong>Hạt Ho&agrave;ng Kim&nbsp;</strong>&ndash; loại bảo dược hiếm c&oacute; trong tự nhi&ecirc;n, hấp thụ linh kh&iacute; của đất trời mấy ngh&igrave;n năm mới vươn l&ecirc;n khỏi l&ograve;ng đất, đơm hoa kết tr&aacute;i. Ph&agrave;m l&agrave; người tu luyện v&otilde; c&ocirc;ng, bất kể theo trường ph&aacute;i n&agrave;o, khi sử dụng loại quả n&agrave;y đều c&oacute; thể gia tăng c&ocirc;ng lực bội phần.</p>\r\n\r\n<p>Nay, những kỳ nh&acirc;n dị sĩ trong giang hồ vừa loan tin Quả Huy Ho&agrave;ng v&agrave; Quả Ho&agrave;ng Kim sắp xuất hiện trở lại, v&agrave; ở những khu vực mu&ocirc;n tr&ugrave;ng hiểm trở như Trường Bạch Sơn quanh năm tuyết gi&aacute;, hoặc c&oacute; thể l&agrave; Mạn Bắc Thảo Nguy&ecirc;n xa x&ocirc;i c&aacute;ch trở. Thi&ecirc;n hạ x&ocirc;n xao, giang hồ lại sắp một phen biến động, giao tranh&hellip;</p>\r\n\r\n<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\">\r\n	<tbody>\r\n		<tr>\r\n			<td><strong>T&ecirc;n</strong></td>\r\n			<td>CHI TIẾT</td>\r\n		</tr>\r\n		<tr>\r\n			<td><img alt=\"Hạt huy hoàng\" src=\"http://khangthien.com/wp-content/uploads/2020/08/hathh.png\" style=\"height:63px; width:79px\" />\r\n			<p>&nbsp;</p>\r\n\r\n			<p><strong>C&Acirc;Y HUY HO&Agrave;NG</strong></p>\r\n			</td>\r\n			<td>\r\n			<ul>\r\n				<li>Thời gian xuất hiện: 20h00</li>\r\n				<li>xuất hiện ngẫu nhi&ecirc;n tại: thục cương sơn, ho&agrave;ng h&agrave; nguy&ecirc;n đầu, kiếm c&aacute;c t&acirc;y bắc, trường giang nguy&ecirc;n đầu,l&acirc;m du quan,&nbsp; dương trung động, v&ocirc; danh động, trường bạch sơn bắc, trường bạch sơn nam, mạc cao quật, phong lăng độ, hoa sơn ph&aacute;i, hắc xa động, thạch cổ trấn, dược vương cốc</li>\r\n				<li>Sau khi xuất hiện 5 ph&uacute;t sau c&oacute; thể h&aacute;i</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td><img alt=\"\" src=\"http://khangthien.com/wp-content/uploads/2020/08/quahh03.jpg\" style=\"height:31px; width:32px\" />\r\n			<p>&nbsp;</p>\r\n\r\n			<p><strong>QUẢ HUY HO&Agrave;NG TIỂU</strong></p>\r\n			</td>\r\n			<td>\r\n			<ul>\r\n				<li>cấp độ c&oacute; thể h&aacute;i: dưới 89</li>\r\n				<li>Phần thưởng: 500.000 điểm kinh nghiệm kh&ocirc;ng cộng dồn</li>\r\n				<li>Giới hạn: 5 quả / 1 nh&acirc;n vật / 1 ng&agrave;y</li>\r\n				<li>Sau khi ch&iacute;n 10 gi&acirc;y sau c&oacute; thể h&aacute;i</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td><img alt=\"\" src=\"http://khangthien.com/wp-content/uploads/2020/08/quahh03.jpg\" style=\"height:31px; width:32px\" />\r\n			<p>&nbsp;</p>\r\n\r\n			<p><strong>QUẢ HUY HO&Agrave;NG TRUNG</strong></p>\r\n			</td>\r\n			<td>\r\n			<ul>\r\n				<li>cấp độ c&oacute; thể h&aacute;i: dưới 89</li>\r\n				<li>Phần thưởng: 2.000.000 điểm kinh nghiệm kh&ocirc;ng cộng dồn</li>\r\n				<li>Giới hạn: 5 quả / 1 nh&acirc;n vật / 1 ng&agrave;y</li>\r\n				<li>Sau khi ch&iacute;n 10 gi&acirc;y sau c&oacute; thể h&aacute;i</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td><img alt=\"\" src=\"http://khangthien.com/wp-content/uploads/2020/08/quahh03.jpg\" style=\"height:31px; width:32px\" />\r\n			<p>&nbsp;</p>\r\n\r\n			<p><strong>QUẢ HUY HO&Agrave;NG CAO</strong></p>\r\n			</td>\r\n			<td>\r\n			<ul>\r\n				<li>cấp độ c&oacute; thể h&aacute;i: dưới 89</li>\r\n				<li>Phần thưởng: 5.000.000 điểm kinh nghiệm kh&ocirc;ng cộng dồn</li>\r\n				<li>Giới hạn: 5 quả / 1 nh&acirc;n vật / 1 ng&agrave;y</li>\r\n				<li>Sau khi ch&iacute;n 10 gi&acirc;y sau c&oacute; thể h&aacute;i</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>C&Acirc;Y HO&Agrave;NG KIM</strong></td>\r\n			<td>\r\n			<ul>\r\n				<li>CHƯA XUẤT HIỆN</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>QUẢ HO&Agrave;NG KIM</strong></td>\r\n			<td>\r\n			<ul>\r\n				<li>CHƯA XUẤT HIỆN</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n', '2022-01-14 14:27:40', NULL, 'http://khangthien.com/wp-content/uploads/2020/08/qua-huy-hoang-khuay-dong-vo-lam-truyen-ky-cong-thanh-chien-120x75.jpg');
INSERT INTO `blog_posts_seo` VALUES (28, 'Boss Tiểu Hoàng Kim và Maps xuất hiện', 'boss-tieu-hoang-kim-va-maps-xuat-hien', NULL, '<p>Boss Tiểu Ho&agrave;ng Kim sẽ xuất hiện v&agrave;o 12 Giờ&nbsp;- 21 Giờ 45 h&agrave;ng ng&agrave;y. C&aacute; nh&acirc;n ti&ecirc;u diệt Boss sẽ nhận được 5 triệu kinh nghiệm v&agrave; ngẫu nhi&ecirc;n vật phẩm qu&yacute; hiếm trong thi&ecirc;n hạ. Ch&uacute;c qu&yacute; nh&acirc;n sĩ c&oacute; được chiến thắng tuyệt đối trước Boss khủng Tiểu Ho&agrave;ng Kim.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\">\r\n	<tbody>\r\n		<tr>\r\n			<td><strong>BOSS</strong></td>\r\n			<td>CHI TIẾT</td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>LIỄU THANH THANH</strong></td>\r\n			<td>\r\n			<ul>\r\n				<li>Bản đồ xuất hiện: Map M&ocirc;n Ph&aacute;i Đường M&ocirc;n&nbsp;&amp; Ngũ Độc</li>\r\n				<li>Phần thưởng: 5triệu exp cho người giết v&agrave; tổ đội, 1tr5 cho người xung quanh</li>\r\n				<li>Rơi: đồ xanh, mật tịch, b&iacute; k&iacute;p 90 ,&nbsp;thủy tinh, ph&uacute;c duy&ecirc;n, ti&ecirc;n thảo lộ, vv</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>DIỆU NHƯ</strong></td>\r\n			<td>\r\n			<ul>\r\n				<li>Bản đồ xuất hiện: Map M&ocirc;n Ph&aacute;i Nga My &amp; Th&uacute;y Y&ecirc;n</li>\r\n				<li>Phần thưởng: 5triệu exp cho người giết v&agrave; tổ đội, 1tr5 cho người xung quanh</li>\r\n				<li>Rơi: đồ xanh, mật tịch, b&iacute; k&iacute;p 90 ,&nbsp;thủy tinh, ph&uacute;c duy&ecirc;n, ti&ecirc;n thảo lộ, vv</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>TRƯƠNG T&Ocirc;NG CH&Iacute;NH</strong></td>\r\n			<td>\r\n			<ul>\r\n				<li>Bản đồ xuất hiện: Map M&ocirc;n Ph&aacute;i V&otilde; Đang &amp; C&ocirc;n L&ocirc;n</li>\r\n				<li>Phần thưởng: 5triệu exp cho người giết v&agrave; tổ đội, 1tr5 cho người xung quanh</li>\r\n				<li>Rơi: đồ xanh, mật tịch, b&iacute; k&iacute;p 90 , thủy tinh, ph&uacute;c duy&ecirc;n, ti&ecirc;n thảo lộ, vv</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>H&Agrave; NH&Acirc;N NG&Atilde;</strong></td>\r\n			<td>\r\n			<ul>\r\n				<li>Bản đồ xuất hiện: Map M&ocirc;n Ph&aacute;i C&aacute;i Bang &amp; Thi&ecirc;n Nhẫn</li>\r\n				<li>Phần thưởng: 5triệu exp cho người giết v&agrave; tổ đội, 1tr5 cho người xung quanh</li>\r\n				<li>Rơi: đồ xanh, mật tịch, B&iacute; K&iacute;p 90 , thủy tinh, ph&uacute;c duy&ecirc;n, ti&ecirc;n thảo lộ, vv</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>TỊNH TH&Ocirc;NG</strong></td>\r\n			<td>\r\n			<ul>\r\n				<li>Bản đồ xuất hiện: Map M&ocirc;n Ph&aacute;i Thi&ecirc;n Vương &amp; Thiếu L&acirc;m</li>\r\n				<li>Phần thưởng: 5triệu exp cho người giết v&agrave; tổ đội, 1tr5 cho người xung quanh</li>\r\n				<li>Rơi: đồ xanh, mật tịch, b&iacute; k&iacute;p 90 , thủy tinh, ph&uacute;c duy&ecirc;n, ti&ecirc;n thảo lộ, vv</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>&nbsp;</td>\r\n			<td>&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>&nbsp;</td>\r\n			<td>&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>&nbsp;</td>\r\n			<td>&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>&nbsp;</td>\r\n			<td>&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>&nbsp;</td>\r\n			<td>&nbsp;</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n', '2022-01-14 14:28:36', NULL, 'http://khangthien.com/wp-content/uploads/2021/05/32-120x75.jpg');
INSERT INTO `blog_posts_seo` VALUES (29, 'Hướng dẫn đường lên Map Train từ 1x – 8x', 'huong-dan-duong-len-map-train-tu-1x-8x', NULL, '<p>Nhằm trợ gi&uacute;p cho T&acirc;n Thủ con đường chinh phục giang hồ v&agrave; nỗi kh&oacute; khăn kiếm đường l&ecirc;n b&atilde;i train trong qu&aacute; tr&igrave;nh b&ocirc;n tẩu, BQT xin hướng dẫn đường l&ecirc;n 1 số map train để anh em dễ d&agrave;ng hơn. Hiện Thần H&agrave;nh Ph&ugrave; chỉ hỗ trợ đưa l&ecirc;n map 90 n&ecirc;n BQT sẽ hướng dẫn map từ cấp 10 &ndash; 89:</p>\r\n\r\n<p><img src=\"https://i.imgur.com/OBxRsx8.png\" /></p>\r\n\r\n<p><img alt=\"????\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/1f449.png\" style=\"height:16px; width:16px\" />&nbsp;Cấp 10 &gt; 19</p>\r\n\r\n<p>&mdash;&mdash;&mdash;&mdash;&mdash;&ndash;</p>\r\n\r\n<p>Xung quanh khu vực Th&agrave;nh Thị</p>\r\n\r\n<p>Xung quanh Thập Đại M&ocirc;n Ph&aacute;i</p>\r\n\r\n<p>Hoa Sơn Cảnh Kỹ Trường</p>\r\n\r\n<p>&ndash; Đường đi: Xa Phu -&gt; Hoa Sơn Cảnh Kỹ Trường</p>\r\n\r\n<p>Dược vương cốc</p>\r\n\r\n<p>&ndash; Đường đi: Phượng Tường -&gt; Long M&ocirc;n Trấn &gt; Dược Vương Cốc</p>\r\n\r\n<p>Mật thất Mộc Nh&acirc;n</p>\r\n\r\n<p>&ndash; Đường đi: M&ocirc;n ph&aacute;i Thiếu L&acirc;m -&gt; Đạt Ma Đường -&gt; Đi v&agrave;o ph&iacute;a sau bức tượng phật</p>\r\n\r\n<p>Nam Nhạc Trấn</p>\r\n\r\n<p>&ndash; Đường đi: Tương Dương -&gt; Ba Lăng Huyện -&gt; Nam Nhạc Trấn</p>\r\n\r\n<p>Nhạn Đ&atilde;ng Sơn</p>\r\n\r\n<p>&ndash; Đường đi: L&acirc;m An -&gt; Long Tuyền Th&ocirc;n &gt; Nhạn Đ&atilde;ng Sơn</p>\r\n\r\n<p>Thi&ecirc;n nhẫn gi&aacute;o tầng 1</p>\r\n\r\n<p>&ndash; Đường đi: Biện Kinh -&gt; Thi&ecirc;n Nhẫn Gi&aacute;o -&gt; Thi&ecirc;n nhẫn gi&aacute;o địa thất</p>\r\n\r\n<p>Thi&ecirc;n nhẫn gi&aacute;o tầng 2</p>\r\n\r\n<p>&ndash; Đường đi: Biện Kinh -&gt; Thi&ecirc;n Nhẫn Gi&aacute;o -&gt; Thi&ecirc;n nhẫn gi&aacute;o địa thất -&gt; Tầng 2</p>\r\n\r\n<p><img alt=\"????\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/1f449.png\" style=\"height:16px; width:16px\" />&nbsp;Cấp 20 &gt; 29</p>\r\n\r\n<p>&mdash;&mdash;&mdash;&mdash;&mdash;&ndash;</p>\r\n\r\n<p>Kiếm C&aacute;c Thục Đạo</p>\r\n\r\n<p>&ndash; Đường đi: Phượng Tường Nam -&gt; Kiếm C&aacute;c Thục Đạo</p>\r\n\r\n<p>Kiếm C&aacute;c T&acirc;y Nam</p>\r\n\r\n<p>&ndash; Đường đi: Th&agrave;nh Độ Bắc -&gt; Kiếm c&aacute;c t&acirc;y Nam</p>\r\n\r\n<p>Kiếm C&aacute;c Trung Nguy&ecirc;n</p>\r\n\r\n<p>&ndash; Đường đi: Biện Kinh Nam -&gt; Phục ngưu sơn T&acirc;y -&gt; Thi&ecirc;n T&acirc;m Động -&gt; Kiếm C&aacute;c</p>\r\n\r\n<p>hoặc Tương Dương Bắc -&gt; Phục Ngưu Sơn -&gt; Thi&ecirc;n T&acirc;m Động -&gt; Kiếm C&aacute;c</p>\r\n\r\n<p>Vũ Lăng Sơn</p>\r\n\r\n<p>&ndash; Đường đi: Tương Dương -&gt; Ba Lăng Huyện -&gt; Vũ Lăng Sơn</p>\r\n\r\n<p>Tần Lăng</p>\r\n\r\n<p>&ndash; Đường đi: Phượng Tường Đ&ocirc;ng -&gt; Tần Lăng</p>\r\n\r\n<p>Phục Lưu Động</p>\r\n\r\n<p>&ndash; Đường đi: Tương Dương -&gt; Ba Lăng Huyện -&gt; Vũ Lăng Sơn -&gt; Phục Lưu Động</p>\r\n\r\n<p>Bạch Thủy Động</p>\r\n\r\n<p>&ndash; Đường đi: Tương Dương -&gt; Ba Lăng Huyện -&gt; Vũ Lăng Sơn -&gt; Bạch Thủy Động</p>\r\n\r\n<p><img alt=\"????\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/1f449.png\" style=\"height:16px; width:16px\" />&nbsp;Cấp 30 &gt; 39</p>\r\n\r\n<p>&mdash;&mdash;&mdash;&mdash;&mdash;&ndash;</p>\r\n\r\n<p>Thổ Phỉ Động.</p>\r\n\r\n<p>&ndash; Đường đi: Đại L&yacute; Phủ -&gt; Điểm Thương Sơn -&gt; Thổ Phỉ Động</p>\r\n\r\n<p>Bạch V&acirc;n Động.</p>\r\n\r\n<p>&ndash; Đường đi: Th&agrave;nh Đ&ocirc; T&acirc;y -&gt; Thanh Th&agrave;nh Sơn -&gt; Bạch V&acirc;n Động</p>\r\n\r\n<p>Kim Quang Động</p>\r\n\r\n<p>&ndash; Đường đi: Phượng Tường Nam -&gt; Kiếm C&aacute;c Thục Đạo -&gt; Kim Quang Động</p>\r\n\r\n<p>M&ecirc; Cung Lăng Tần Thủy Ho&agrave;ng</p>\r\n\r\n<p>&ndash; Đường đi: Phượng Tường -&gt; Tần Lăng -&gt; M&ecirc; Cung Lăng Tần Thủy Ho&agrave;ng</p>\r\n\r\n<p>Toả V&acirc;n Động</p>\r\n\r\n<p>&ndash; Đường đi: Phượng Tường -&gt; Kiếm C&aacute;c Thục Đạo -&gt; Kim Quang Động -&gt; Toả V&acirc;n Động</p>\r\n\r\n<p>Tuyết B&aacute;o Động</p>\r\n\r\n<p>&ndash; Đường đi: Phượng Tường -&gt; Long M&ocirc;n Trấn &gt; Dược Vương Cốc &ndash; Tuyết B&aacute;o Động</p>\r\n\r\n<p>Yến Tử Động</p>\r\n\r\n<p>&ndash; Đường đi: Tương Dương -&gt; Ba Lăng Huyện -&gt; Mi&ecirc;u Lĩnh -&gt; Yến Tử Động</p>\r\n\r\n<p>hoặc Thần H&agrave;nh Ph&ugrave; -&gt; Khỏa Lăng Động -&gt; Đi ngược về Yến Tử Động.</p>\r\n\r\n<p>Thục Cương Sơn</p>\r\n\r\n<p>&ndash; Đường đi: Dương Ch&acirc;u T&acirc;y -&gt; Thục Cương Sơn</p>\r\n\r\n<p>Vũ Di Sơn</p>\r\n\r\n<p>&ndash; Đường đi: L&acirc;m An -&gt; Long Tuyền Th&ocirc;n -&gt; Vũ Di Sơn hoặc Ngũ Độc Gi&aacute;o -&gt; Vũ Di Sơn</p>\r\n\r\n<p>Điểm Thương Sơn</p>\r\n\r\n<p>&ndash; Đường đi: Đại L&yacute; -&gt; Điểm Thương Sơn</p>\r\n\r\n<p>Thanh Th&agrave;nh Sơn</p>\r\n\r\n<p>&ndash; Đường đi: Th&agrave;nh Đ&ocirc; T&acirc;y -&gt; Thanh Th&agrave;nh Sơn</p>\r\n\r\n<p><img alt=\"????\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/1f449.png\" style=\"height:16px; width:16px\" />&nbsp;Cấp 40 &gt; 49</p>\r\n\r\n<p>&mdash;&mdash;&mdash;&mdash;&mdash;&ndash;</p>\r\n\r\n<p>Điểm Thương Động tầng 1,2,3.</p>\r\n\r\n<p>&ndash; Đường đi: Đại L&yacute; -&gt; Điểm Thương Sơn -&gt; Điểm Thương Động</p>\r\n\r\n<p>Thần Ti&ecirc;n Động</p>\r\n\r\n<p>&ndash; Đường đi: Th&agrave;nh Đ&ocirc; T&acirc;y -&gt; Thanh Th&agrave;nh Sơn -&gt; Thần Ti&ecirc;n Động</p>\r\n\r\n<p>Kinh Ho&agrave;ng Động</p>\r\n\r\n<p>&ndash; Đường đi: Th&agrave;nh Đ&ocirc; Bắc -&gt; Kiếm c&aacute;c t&acirc;y Nam -&gt; Kinh Ho&agrave;ng Động</p>\r\n\r\n<p><img alt=\"????\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/1f449.png\" style=\"height:16px; width:16px\" />&nbsp;Cấp 50 &gt; 59</p>\r\n\r\n<p>&mdash;&mdash;&mdash;&mdash;&mdash;&ndash;</p>\r\n\r\n<p>Tường V&acirc;n Động tầng 1.</p>\r\n\r\n<p>&ndash; Đường đi: Dương Ch&acirc;u Bắc -&gt; C&aacute;i Bang -&gt; Tường V&acirc;n Động.</p>\r\n\r\n<p>M&ecirc; Cung Thiết Th&aacute;p tầng 1,2,3.</p>\r\n\r\n<p>&ndash; Đường đi: Bi&ecirc;n Kinh T&acirc;y -&gt; M&ecirc; Cung Thi&ecirc;t Th&aacute;p</p>\r\n\r\n<p>Thi&ecirc;n T&acirc;m Th&aacute;p tầng 1,2.</p>\r\n\r\n<p>&ndash; Đường đi: Đại L&yacute; Phủ -&gt; Thi&ecirc;n T&acirc;m Th&aacute;p</p>\r\n\r\n<p>&Aacute;c b&aacute; địa đạo.</p>\r\n\r\n<p>&ndash; Đường đi: Đại L&yacute; Phủ -&gt; &Aacute;c b&aacute; địa đạo</p>\r\n\r\n<p>Thi&ecirc;n T&acirc;m Động</p>\r\n\r\n<p>&ndash; Đường đi: Biện Kinh Nam -&gt; Phục Ngưu Sơn -&gt; Thi&ecirc;n T&acirc;m Động</p>\r\n\r\n<p>Hương Thuỷ Động</p>\r\n\r\n<p>&ndash; Đường đi: Th&agrave;nh Đ&ocirc; T&acirc;y -&gt; Thanh Th&agrave;nh Sơn -&gt; Hương Thuỷ Động.</p>\r\n\r\n<p>Ngọc Hoa Động</p>\r\n\r\n<p>&ndash; Đường đi: Ngũ Độc Gi&aacute;o -&gt; Vũ Di Sơn -&gt; Bảo Ngọc Hoa Động</p>\r\n\r\n<p>Nghiệt Long Động</p>\r\n\r\n<p>&ndash; Đường đi: Long Tuyền th&ocirc;n -&gt; La Ti&ecirc;u Sơn-&gt; Nghiệt Long Động</p>\r\n\r\n<p>Sơn động dưới đ&aacute;y Động đ&igrave;nh Hồ tầng 1 2</p>\r\n\r\n<p>&ndash; Đường đi: Ba Lăng Huyện -&gt; Bến T&agrave;u -&gt; Thi&ecirc;n Vương Đảo -&gt; Động định Hồ</p>\r\n\r\n<p><img alt=\"????\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/1f449.png\" style=\"height:16px; width:16px\" />&nbsp;Cấp 60 &gt; 69</p>\r\n\r\n<p>&mdash;&mdash;&mdash;&mdash;&mdash;&ndash;</p>\r\n\r\n<p>Tường V&acirc;n Động tầng 2,3,4.</p>\r\n\r\n<p>&ndash; Đường đi: Dương Ch&acirc;u T&acirc;y -&gt; C&aacute;i Bang -&gt; Tường V&acirc;n Động</p>\r\n\r\n<p>Thi&ecirc;n T&acirc;m Th&aacute;p tầng 3</p>\r\n\r\n<p>&ndash; Đường đi: Đại L&yacute; Phủ -&gt; Thi&ecirc;n T&acirc;m Th&aacute;p</p>\r\n\r\n<p>108 La H&aacute;n Trận</p>\r\n\r\n<p>&ndash; Đường đi: Bi&ecirc;n Kinh Nam -&gt; Thiếu L&acirc;m Tự -&gt; La H&aacute;n Đường -&gt; đi ph&iacute;a sau tượng Phật -&gt; 108 La H&aacute;n Trận</p>\r\n\r\n<p>Nha M&ocirc;n Mật Đạo</p>\r\n\r\n<p>&ndash; Đường đi: Tương Dương Phủ -&gt; Nha M&ocirc;n Mật Đạo</p>\r\n\r\n<p>Dương Gi&aacute;c Động</p>\r\n\r\n<p>&ndash; Đường đi: Long Tuyền Th&ocirc;n -&gt; Nhạn Đ&atilde;ng Sơn-&gt;Dương Gi&aacute;c Động</p>\r\n\r\n<p>Thi&ecirc;n Nh&acirc;n Gi&aacute;o Th&aacute;nh Động</p>\r\n\r\n<p>&ndash; Đường đi: Biện Kinh Bắc -&gt; Thi&ecirc;n Nhẫn Gi&aacute;o -&gt; Thi&ecirc;n Nhẫn Địa Thất -&gt; Tầng 3 Thi&ecirc;n Nhẫn Gi&aacute;o -&gt; Thi&ecirc;n Nhẫn Gi&aacute;o Th&aacute;nh Động</p>\r\n\r\n<p>Ho&agrave;nh Sơn Ph&aacute;i</p>\r\n\r\n<p>&ndash; Đường đi: Ba Lăng Huyện -&gt; Nam Nhạc Trấn -&gt; Ho&agrave;nh Sơn Ph&aacute;i</p>\r\n\r\n<p>Linh Cốc Động</p>\r\n\r\n<p>&ndash; Đường đi: Dương Ch&acirc;u T&acirc;y -&gt; Thục Cương Sơn -&gt; Linh Cốc Động</p>\r\n\r\n<p>hoặc Thần H&agrave;nh Ph&ugrave; -&gt; Tiến C&uacute;c Động -&gt; Linh Cốc Động</p>\r\n\r\n<p>Thanh Loa Đảo</p>\r\n\r\n<p>&ndash; Đường đi: Ba Lăng Huyện -&gt; Bến T&agrave;u -&gt; Thi&ecirc;n Vương Đảo -&gt; Thuyền Phu Thi&ecirc;n Vương ( Y&ecirc;u cầu: TVB phải l&agrave;m nhiệm vụ Xuất Sư mới c&oacute; thể l&ecirc;n được )</p>\r\n\r\n<p>Thanh Loa Đảo Sơn Động</p>\r\n\r\n<p>&ndash; Đường đi: Ba Lăng Huyện -&gt; Bến T&agrave;u -&gt; Thi&ecirc;n Vương Đảo -&gt; Thanh Loa Sơn Động</p>\r\n\r\n<p>Tầng 5 Tuyết b&aacute;o động</p>\r\n\r\n<p>&ndash; Đường đi: Phượng Tường -&gt; Long M&ocirc;n Trấn &gt; Dược Vương Cốc &ndash; Tuyết B&aacute;o Động</p>\r\n\r\n<p><img alt=\"????\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/1f449.png\" style=\"height:16px; width:16px\" />&nbsp;Cấp 70 &gt; 79</p>\r\n\r\n<p>&mdash;&mdash;&mdash;&mdash;&mdash;&ndash;</p>\r\n\r\n<p>L&acirc;m Du Quan</p>\r\n\r\n<p>&ndash; Đường đi: Biện Kinh Bắc -&gt; L&acirc;m Du Quan</p>\r\n\r\n<p>L&atilde;o Hổ Động</p>\r\n\r\n<p>&ndash; Đường đi: Long M&ocirc;n Trấn -&gt; Ho&agrave;ng H&agrave; Nguy&ecirc;n Đầu -&gt; L&atilde;o Hổ Động</p>\r\n\r\n<p>M&ecirc; cung Lăng Tần Thủy Ho&agrave;ng tầng 3</p>\r\n\r\n<p>&ndash; Đường đi: Phượng Tường Bắc -&gt; Tần Lăng -&gt; Lăng Tần Thủy Ho&agrave;ng -&gt; 1 -&gt; 2 -&gt; 3</p>\r\n\r\n<p>Dược Vương Động tầng 2</p>\r\n\r\n<p>&ndash; Đường đi: Long M&ocirc;n Trấn -&gt; Dược Vương Cốc -&gt; Dược Vương Động</p>\r\n\r\n<p>Đ&agrave;o Hoa Nguy&ecirc;n</p>\r\n\r\n<p>&ndash; Đường đi: Ba Lăng Huyện -&gt; Vũ Lăng Sơn -&gt; Bạch Thủy Động -&gt; Phục Lưu Động -&gt; Đ&agrave;o Hoa Nguy&ecirc;n</p>\r\n\r\n<p>Lưu Ti&ecirc;n Động tầng 6</p>\r\n\r\n<p>&ndash; Đường đi: Long M&ocirc;n Trấn -&gt; Ho&agrave;ng H&agrave; Nguy&ecirc;n Đầu -&gt; Lưu Ti&ecirc;n Động</p>\r\n\r\n<p>Đại T&ugrave; Động</p>\r\n\r\n<p>&ndash; Đường đi: Ba Lăng Huyện -&gt; Vũ Lăng Sơn -&gt; Đại T&ugrave; Động</p>\r\n\r\n<p>Long Nh&atilde;n Động</p>\r\n\r\n<p>&ndash; Đường đi: Đại L&yacute; -&gt; Điểm Thương Sơn -&gt; Long Nh&atilde;n Động</p>\r\n\r\n<p><img alt=\"????\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/1f449.png\" style=\"height:16px; width:16px\" />&nbsp;Cấp 80 &gt; 89</p>\r\n\r\n<p>&mdash;&mdash;&mdash;&mdash;&mdash;&ndash;</p>\r\n\r\n<p>V&ocirc; Danh Động</p>\r\n\r\n<p>&ndash; Đường đi: Đại L&yacute; Phủ -&gt; Thạch Cổ Trấn -&gt; V&ocirc; Danh Động</p>\r\n\r\n<p>Lưỡng Thuỷ Động</p>\r\n\r\n<p>&ndash; Đường đi: L&acirc;m An Phủ -&gt; Long Tuyền Th&ocirc;n -&gt; Nh&atilde;n Đăng Sơn -&gt; Lưỡng Thuỷ Động</p>\r\n\r\n<p>Thanh Kh&ecirc; Động</p>\r\n\r\n<p>&ndash; Đường đi: L&acirc;m An Phủ -&gt; Long Tuyền Th&ocirc;n -&gt; Thanh Kh&ecirc; Động.</p>\r\n\r\n<p>Sa mạc địa biểu</p>\r\n\r\n<p>&ndash; Đường đi: Long M&ocirc;n Trấn -&gt; C&ocirc;n L&ocirc;n Ph&aacute;i -&gt; Kho&aacute;i Hoạt L&acirc;m -&gt; chạy lại tọa độ 214/196 (H&igrave;nh ảnh hướng dẫn)</p>\r\n\r\n<p>Ch&acirc;n n&uacute;i trường Bạch</p>\r\n\r\n<p>&ndash; Đường đi: Biện Kinh Bắc -&gt; L&acirc;m Du Quan -&gt; Ch&acirc;n N&uacute;i Trường Bạch</p>\r\n\r\n<p>Băng H&agrave; Động</p>\r\n\r\n<p>&ndash; Đường đi: Phượng Tường -&gt; Vĩnh Lạc Trấn -&gt; Băng H&agrave; Động</p>\r\n\r\n<p>Ph&ugrave; Dung Động</p>\r\n\r\n<p>&ndash; Đường đi: Th&agrave;nh Độ -&gt; Giang T&acirc;n Th&ocirc;n -&gt; Ph&ugrave; Dung Động</p>\r\n\r\n<p>Tuyết b&aacute;o động tầng 8</p>\r\n\r\n<p>&ndash; Đường đi: Phượng Tường -&gt; Long M&ocirc;n Trấn &gt; Dược Vương Cốc &ndash; Tuyết B&aacute;o Động</p>\r\n', '2022-01-14 14:29:18', NULL, 'http://khangthien.com/wp-content/uploads/2021/04/dong-120x75.png');
INSERT INTO `blog_posts_seo` VALUES (31, 'Lịch Bảo Trì Định Kỳ Hàng Ngày - Thời Gian : Từ 07 giờ đến 07 giờ 10 Phút ( Sáng )', 'lich-bao-tri-dinh-ky-hang-ngay-thoi-gian-tu-07-gio-den-07-gio-10-phut-sang', NULL, '<p><img alt=\"\" src=\"/library/images/thienlong/a2-6.png\" />Thời Gian Bảo Tr&igrave; Định Kỳ H&agrave;ng Ng&agrave;y&nbsp;</p>\r\n\r\n<p>Từ :&nbsp; 07 giờ s&aacute;ng đến 07 giờ 10 ph&uacute;t&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:center\"><img alt=\"\" src=\"https://jx1hoiuc.mobi/static/files/uploads/images/baiviet/a2-6.png\" style=\"height:422px; width:593px\" /></p>\r\n\r\n<h2><strong>&nbsp;</strong></h2>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:center\">&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h4>&nbsp;</h4>\r\n', '2022-03-06 14:44:13', NULL, 'https://jx1hoiuc.mobi/static/files/uploads/images/bảo trì định kì.png');
INSERT INTO `blog_posts_seo` VALUES (34, 'Giới thiệu Máy Chủ S1 Thiên Sơn Tái Khởi - Thử Nghiệm : 19 giờ , Ngày 02 Tháng 05 Năm 2025 - OPEN Beta : 19 , Ngày 09 Tháng 05 Năm 2025 ( Thứ 6 )', 'gioi-thieu-may-chu-s1-thien-son-tai-khoi-thu-nghiem-19-gio-ngay-02-thang-05-nam-2025-open-beta-19-ngay-09-thang-05-nam-2025-thu-6', NULL, '<p>Th&acirc;n gửi qu&yacute; nh&acirc;n sĩ,</p>\r\n\r\n<p><strong>M&aacute;y chủ <span style=\"font-size:16px\">S1 Thi&ecirc;n Sơn T&aacute;i Khởi&nbsp;</span></strong>&ndash;&nbsp;<strong>ho&agrave;n to&agrave;n miễn ph&iacute; giờ chơi</strong>. Khởi đầu h&agrave;nh tr&igrave;nh mới đưa tất cả nh&acirc;n sĩ vươn tầm cao thật sự tại chốn giang hồ. Cơ hội kh&aacute;m ph&aacute; v&agrave; chinh phục v&ugrave;ng đất mới lu&ocirc;n l&agrave; niềm vui của những thủ lĩnh v&otilde; l&acirc;m, sẵn s&agrave;ng chờ ng&agrave;y khai mở để x&ocirc;ng pha chiến trận nh&eacute;.</p>\r\n\r\n<p>Ch&uacute;ng t&ocirc;i đảm bảo một Server ổn định, với hệ thống đồ xanh l&agrave; chủ đạo, cao cấp nhất chỉ l&agrave; đồ HKMP, c&oacute; thể kiếm HKMP từ việc ho&agrave;n th&agrave;nh 6000 nhiệm vụ D&atilde; Tẩu hoặc săn Boss Ho&agrave;ng Kim, tiền vạn kh&ocirc;ng lạm ph&aacute;t v&agrave; c&ugrave;ng&nbsp;với đội ngũ BQT nhiều kinh nghiệm, th&acirc;n thiện, nhiệt t&igrave;nh, sẽ gi&uacute;p c&aacute;c bạn c&oacute; một s&acirc;n chơi l&acirc;u d&agrave;i, gắn kết v&agrave; kh&ocirc;ng nh&agrave;m ch&aacute;n.</p>\r\n\r\n<p>Quan trọng hơn hết l&agrave; Server thường xuy&ecirc;n cập nhất c&aacute;c t&iacute;nh năng v&agrave; c&aacute;c vật phẩm độc quyền th&uacute; vị, cũng như tổ chức c&aacute;c giải đấu lớn Thi&ecirc;n Hạ Đệ Nhất Bang, V&otilde; L&acirc;m Minh Chủ với phần thưởng v&ocirc; c&ugrave;ng gi&aacute; trị m&agrave; kh&ocirc;ng Server n&agrave;o c&oacute; được.</p>\r\n\r\n<p style=\"text-align:center\"><img alt=\"\" src=\"https://jx1hoiuc.mobi/static/files/uploads/images/Dự án mới 146.png\" style=\"height:356px; width:900px\" /></p>\r\n\r\n<h2><strong>&nbsp;Thời Gian</strong></h2>\r\n\r\n<table align=\"center\">\r\n	<tbody>\r\n		<tr>\r\n			<td><strong>Nội dung</strong></td>\r\n			<td><strong>Chi tiết</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>Alpha Test mở m&aacute;y chủ thử nghiệm</strong></td>\r\n			<td>Từ <strong>19h00</strong> ng&agrave;y 02/05 đến 23h59 ng&agrave;y 08/05/2025</td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>Ch&iacute;nh thức khai mở m&aacute;y chủ</strong></td>\r\n			<td>L&uacute;c <strong>19h00</strong> ng&agrave;y 09<strong>/05/2025 (Thứ 6)</strong></td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<h3><strong>&nbsp;C&aacute;c th&ocirc;ng tin cơ bản về m&aacute;y chủ <span style=\"font-size:16px\">Hỏa Long Sơn</span></strong></h3>\r\n\r\n<table align=\"center\">\r\n	<tbody>\r\n		<tr>\r\n			<td><strong>Nội dung</strong></td>\r\n			<td><strong>Chi tiết</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td>Phi&ecirc;n bản</td>\r\n			<td>NỘI C&Ocirc;NG &ndash; HỆ MỘC TH&Acirc;N PH&Aacute;P &ndash; ĐỒ XANH &ndash; MIỄN PH&Iacute;</td>\r\n		</tr>\r\n		<tr>\r\n			<td rowspan=\"2\">Giới hạn Account</td>\r\n			<td>Tối đa 4 Account/PC/IP v&agrave; <strong>Tống Kim 1 Account/ IP</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td>Cấm tuyệt đối k&eacute;o xe tr&ecirc;n 4 acc khi hoạt động game. Trường hợp vi phạm kh&oacute;a nh&acirc;n vật v&agrave; IP game vĩnh viễn.</td>\r\n		</tr>\r\n		<tr>\r\n			<td>VPN đường truyền ri&ecirc;ng mạnh mẽ</td>\r\n			<td>Hệ thống Proxy, VPN đường truyền ri&ecirc;ng cho nh&acirc;n sĩ to&agrave;n cầu, trải nghiệm game mượt m&agrave; như tại Việt Nam.</td>\r\n		</tr>\r\n		<tr>\r\n			<td rowspan=\"2\">Hệ thống Auto</td>\r\n			<td>Hỗ Trợ Auto Train INGAME&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Hỗ trợ Auto PK bang hội , thiện &aacute;c , li&ecirc;n sever&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td rowspan=\"2\">Đặc sắc trong game</td>\r\n			<td>Hệ thống trang bị , vật phẩm mới lạ, đặc sắc. Đặc Biệt t&iacute;nh năng (<strong>Đại Hội V&otilde; L&acirc;m</strong>)</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Giới hạn bang hội 50 nh&acirc;n vật/bang, kh&ocirc;ng số ảo.</td>\r\n		</tr>\r\n		<tr>\r\n			<td colspan=\"2\"><strong>Th&ocirc;ng tin kh&aacute;c</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td>Hệ thống 7 th&agrave;nh thị v&agrave; c&aacute;c th&ocirc;n trấn</td>\r\n			<td>Hệ thống skill m&ocirc;n ph&aacute;i được c&acirc;n bằng. Sự trở lại của c&aacute;c m&ocirc;n ph&aacute;i từng bị l&atilde;ng qu&ecirc;n tại V&otilde; L&acirc;m Truyền Kỳ.</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Sự kiện đua top d&agrave;nh cho Bang hội diễn ra mỗi th&aacute;ng</td>\r\n			<td>C&aacute;c t&iacute;nh năng đặc sắc như C&ocirc;ng Th&agrave;nh Chiến, Tống Kim, Vượt Ải, Phong Lăng Độ, Boss Đại Ho&agrave;ng Kim, Quả Ho&agrave;ng Kim&hellip; được t&aacute;i hiện.</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Luyện skill 9x (C&oacute; Bản Đồ hỗ trợ luyện skill)</td>\r\n			<td>C&aacute;c vật phẩm mới đặc sắc như t&uacute;i y tế, h&agrave;o hiệp lễ bao, bảo rương thương hội&hellip;.</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Ti&ecirc;n Thảo Lộ cấp 60 được sử dụng, giới hạn 8 b&igrave;nh/ng&agrave;y</td>\r\n			<td>Cấp 80 nhận hỗ trợ 01 skill 9x m&ocirc;n ph&aacute;i (trừ VLK)</td>\r\n		</tr>\r\n		<tr>\r\n			<td>C&aacute;c t&iacute;nh năng nổi bật trong game</td>\r\n			<td>\r\n			<ul>\r\n				<li>&nbsp;<strong>MIỄN PH&Iacute;&nbsp;</strong>giờ chơi.</li>\r\n				<li>&nbsp;Hệ Thống AUTO INGAME Đầy Đủ</li>\r\n				<li>&nbsp;Giới Hạn 4 AC / 1 IP Mạng</li>\r\n				<li>&nbsp;Hệ Thống Kỹ Năng 150 Đặc Sắc - C&acirc;n Bằng Ổn Định&nbsp;</li>\r\n				<li>&nbsp;<strong>Mốc 6000 nhiệm vụ D&atilde; Tẩu</strong>&nbsp;nhận ngẫu nhi&ecirc;n 1 trang bị&nbsp;<strong>Ho&agrave;ng Kim M&ocirc;n Ph&aacute;i</strong>.</li>\r\n				<li>&nbsp;C&acirc;n bằng&nbsp;<strong>Tiền Vạn tuyệt đối.</strong></li>\r\n				<li>&nbsp;<strong>Đồ Xanh</strong>&nbsp;cực hiếm v&agrave; gi&aacute; trị cao.</li>\r\n				<li>&nbsp;C&oacute;&nbsp;<strong>hệ thống VPN&nbsp;</strong>hỗ trợ đường truyền tốt nhất cho c&aacute;c anh em ở&nbsp;<strong>Nước Ngo&agrave;i.</strong></li>\r\n				<li>&nbsp;Đầu tư v&agrave;o&nbsp;<strong>chi ph&iacute; Quảng C&aacute;o cực k&igrave; khủng khiếp</strong>.</li>\r\n				<li>&nbsp;Mỗi th&aacute;ng chỉ diễn ra 1 Event</li>\r\n				<li>&nbsp;Kinh nghiệm x2 so với VNG.</li>\r\n				<li>&nbsp;<strong>Chiến Trường Tống Kim</strong>&nbsp;x2&nbsp;điểm trận 21h00 mỗi ng&agrave;y cực k&igrave; đ&ocirc;ng.</li>\r\n				<li>&nbsp;<strong>C&ocirc;ng Th&agrave;nh Chiến - Thất Đại Th&agrave;nh Thị.</strong></li>\r\n				<li>&nbsp;Hệ thống&nbsp;<strong>Boss Đại + Tiểu</strong>&nbsp;cực chuẩn.</li>\r\n				<li>&nbsp;Phi&ecirc;n bản&nbsp;<strong>kết hợp giữa Th&acirc;n ph&aacute;p v&agrave; Nội c&ocirc;ng.</strong></li>\r\n				<li><strong>&nbsp;C&acirc;n bằng M&ocirc;n Ph&aacute;i</strong>&nbsp;tốt nhất thị trường v&otilde; l&acirc;m hiện tại.</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<h2><br />\r\nHỗ Trợ Nh&acirc;n Vật Khi V&agrave;o Game</h2>\r\n\r\n<table align=\"center\">\r\n	<tbody>\r\n		<tr>\r\n			<td><strong>Nội dung</strong></td>\r\n			<td><strong>Chi tiết</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td>Tạo nh&acirc;n vật</td>\r\n			<td>Cấp 1</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Tinh Hồng Bảo Thạch</td>\r\n			<td>V&agrave;o M&ocirc;n Ph&aacute;i - Đại Hiệp Nhận 6 Vi&ecirc;n</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Lam Thủy Tinh</td>\r\n			<td>1 Vi&ecirc;n</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Tử Thủy Tinh,Lục Thủy Tinh</td>\r\n			<td>1 Vi&ecirc;n</td>\r\n		</tr>\r\n		<tr>\r\n			<td>V&ograve;ng S&aacute;ng hồi m&aacute;u, mana</td>\r\n			<td>Đến cấp 70</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Hỗ trợ b&iacute; k&iacute;p 90</td>\r\n			<td>Khi Đạt Cấp 90 -&nbsp; Nhận Miễn Ph&iacute; 1 Cuốn</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Hỗ trợ</td>\r\n			<td>T&uacute;i qu&agrave; đặc biệt</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Khởi Tạo Nh&acirc;n Vật</td>\r\n			<td>C&oacute; thể tạo nh&acirc;n vật ở tất cả c&aacute;c th&ocirc;n</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<h3><strong>&nbsp;&nbsp;</strong><strong>Code Hỗ Trợ T&acirc;n Thủ:</strong><span style=\"font-size:13px\">&nbsp;mỗi nh&acirc;n vật chỉ nhập được 1 lần tại NPC Gift Code</span></h3>\r\n\r\n<table align=\"center\">\r\n	<tbody>\r\n		<tr>\r\n			<td><strong>Nội dung</strong></td>\r\n			<td><strong>Chi tiết</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td>Ti&ecirc;n Thảo Lộ 1h</td>\r\n			<td>02</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Thi&ecirc;n Sơn Bảo Lộ</td>\r\n			<td>02</td>\r\n		</tr>\r\n		<tr>\r\n			<td>B&aacute;ch quả lộ</td>\r\n			<td>02</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Thần H&agrave;nh Ph&ugrave; ( 3 Ng&agrave;y )</td>\r\n			<td>01</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2>Th&ocirc;ng Tin Đua Top M&aacute;y Chủ S1 Thi&ecirc;n Sơn T&aacute;i Khởi&nbsp;<span style=\"font-size:18px\"><strong>:</strong></span></h2>\r\n\r\n<p>Bắt đầu từ: <strong>19h00 09/05/2025</strong>&nbsp;Đến <strong>19h ng&agrave;y 09/06/2025</strong></p>\r\n\r\n<table align=\"center\" border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:500px\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"text-align:center\"><strong>TOP</strong></td>\r\n			<td style=\"text-align:center\"><strong>Phần Thưởng</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"text-align:center\">&nbsp;1</td>\r\n			<td>\r\n			<ul>\r\n				<li><strong>Ngựa Phi V&acirc;n</strong></li>\r\n				<li>2000 Đồng Xu</li>\r\n				<li>100 Li&ecirc;n Đấu Lệnh</li>\r\n				<li>20 Ng&acirc;n Phiếu&nbsp;</li>\r\n				<li>3 v&otilde; l&acirc;m mật tịch</li>\r\n				<li>3 tẩy tuỷ kinh</li>\r\n				<li>Danh Hiệu V&ograve;ng s&aacute;ng Top 1 &quot; Minh Chủ V&otilde; L&acirc;m &quot; ( Vĩnh Viễn )</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"text-align:center\">2</td>\r\n			<td>\r\n			<ul>\r\n				<li><strong>Ngựa Chiếu Dạ Ngọc Sư Tử</strong></li>\r\n				<li>1500 Đồng Xu</li>\r\n				<li>70 Li&ecirc;n Đấu Lệnh</li>\r\n				<li>15 Ng&acirc;n Phiếu</li>\r\n				<li>2 tẩy tuỷ kinh</li>\r\n				<li>2 v&otilde; l&acirc;m mật tịch</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"text-align:center\">3</td>\r\n			<td>\r\n			<ul>\r\n				<li><strong>Ngựa X&iacute;ch Thố&nbsp;</strong></li>\r\n				<li><strong>1000 Đồng Xu</strong></li>\r\n				<li><strong>50 Li&ecirc;n Đấu Lệnh</strong></li>\r\n				<li><strong>10 Ng&acirc;n Phiếu</strong></li>\r\n				<li>1 tẩy tuỷ kinh</li>\r\n				<li>1 v&otilde; l&acirc;m mật tịch</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"text-align:center\">4 - 10</td>\r\n			<td>\r\n			<ul>\r\n				<li><strong>Ngựa Đ&iacute;ch L&ocirc;</strong></li>\r\n				<li>500 Đồng Xu</li>\r\n				<li>20 Li&ecirc;n Đấu Lệnh</li>\r\n				<li>5 Ng&acirc;n Phiếu</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n', '2022-03-21 15:55:19', NULL, 'https://jx1hoiuc.mobi/static/files/uploads/images/Dự án mới 146.png');
INSERT INTO `blog_posts_seo` VALUES (33, 'Nhiệm vụ hằng ngày - Thưởng nhiệm vụ dã tẩu', 'nhiem-vu-hang-ngay-thuong-nhiem-vu-da-tau', NULL, '<p style=\"text-align:center\"><span style=\"color:#1abc9c\"><span style=\"font-size:16px\"><strong>Nhận thưởng nhiệm vụ d&atilde; tẩu, phần thưởng phong ph&uacute;, gi&aacute; trị</strong></span></span></p>\r\n\r\n<p>D&atilde; tẩu l&agrave; nhiệm vụ m&agrave; c&aacute;c nh&acirc;n sỹ c&oacute; thể thực hiện hằng ng&agrave;y, đem lại v&ocirc; c&ugrave;ng nhiều c&aacute;c phần thưởng gi&aacute; trị, phong ph&uacute;.</p>\r\n\r\n<h2><span style=\"color:#1abc9c\"><strong>Vị tr&iacute;</strong></span></h2>\r\n\r\n<p>C&aacute;c nh&acirc;n sỹ c&oacute; thể đến gặp D&atilde; tẩu tại thất đại th&agrave;nh thị v&agrave; 8 t&acirc;n thủ th&ocirc;n để nhận nhiệm vụ.</p>\r\n\r\n<p style=\"text-align:center\"><img alt=\"\" src=\"/library/images/nvdt/ts_datau.png\" /><img alt=\"\" src=\"https://jx1hoiuc.mobi/static/files/uploads/images/baiviet/ts_datau.png\" style=\"height:191px; width:523px\" /></p>\r\n\r\n<p>C&aacute;c nh&acirc;n sỹ ho&agrave;n th&agrave;nh c&aacute;c mốc nhiệm vụ trong ng&agrave;y 10, 20, 30, 40 v&agrave; c&aacute;c mốc t&iacute;nh theo tổng số nhiệm vụ đạt được sẽ nhận được những phần thưởng gi&aacute; trị, phong ph&uacute;.</p>\r\n\r\n<p style=\"text-align:center\"><img alt=\"\" src=\"/library/images/nvdt/ts_thuongmocdatau.png\" /><img alt=\"\" src=\"https://jx1hoiuc.mobi/static/files/uploads/images/baiviet/ts_thuongmocdatau.png\" style=\"height:242px; width:437px\" /></p>\r\n\r\n<p>Trong l&uacute;c l&agrave;m nhiệm vụ c&oacute; thể nhận th&ecirc;m những vật phẩm v&agrave; lượng kinh nghiệm gi&aacute; trị kh&aacute;c.&nbsp;</p>\r\n\r\n<h4><strong>Ngo&agrave;i ra đại hiệp c&oacute; thể ho&agrave;ng th&agrave;nh nhanh nhi&ecirc;m vụ bằng&nbsp;Tử Thuỷ Tinh&nbsp;v&agrave;&nbsp;Lệnh B&agrave;i Ho&agrave;n Th&agrave;nh D&atilde; Tẩu&nbsp;</strong>(mỗi ng&agrave;y d&ugrave;ng lệnh b&agrave;i 10 lần).</h4>\r\n\r\n<h2>Thưởng mốc h&agrave;ng ng&agrave;y v&agrave; mốc d&atilde; tẩu</h2>\r\n\r\n<h3><strong>Mốc 10,20,30,40 h&agrave;ng ng&agrave;y:</strong></h3>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<table align=\"center\" border=\"2\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:500px\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"text-align:left\"><strong>&nbsp; Mốc&nbsp; &nbsp;&nbsp;</strong></td>\r\n			<td style=\"text-align:left\"><strong>Phần Thưởng</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td>10</td>\r\n			<td>\r\n			<p><strong>500.000 Exp</strong></p>\r\n\r\n			<p><strong>Nhận trong 1 những vật phẩm:</strong></p>\r\n\r\n			<p>Thiết la h&aacute;n</p>\r\n\r\n			<p>S&aacute;t thủ giản</p>\r\n\r\n			<p>Bao dược ho&agrave;n</p>\r\n\r\n			<p>Ph&uacute;c duy&ecirc;n lộ (tiểu)</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>20</td>\r\n			<td>\r\n			<p>800.000 Exp</p>\r\n\r\n			<p>Nhận trong 1 những vật phẩm:</p>\r\n\r\n			<p>Thiết la h&aacute;n</p>\r\n\r\n			<p>S&aacute;t thủ giản</p>\r\n\r\n			<p>Bao dược ho&agrave;n</p>\r\n\r\n			<p>Ph&uacute;c duy&ecirc;n lộ (tiểu)</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>30</td>\r\n			<td>\r\n			<p><strong>2.000.000 Exp</strong></p>\r\n\r\n			<p><strong>Nhận trong 1 những vật phẩm:</strong></p>\r\n\r\n			<p>Thiết la h&aacute;n</p>\r\n\r\n			<p>S&aacute;t thủ giản</p>\r\n\r\n			<p>Bao dược ho&agrave;n</p>\r\n\r\n			<p>Ph&uacute;c duy&ecirc;n lộ (Trung)</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>40</td>\r\n			<td>\r\n			<p><strong>3.000.000 Exp</strong></p>\r\n\r\n			<p><strong>Nhận trong 1 những vật phẩm:</strong></p>\r\n\r\n			<p>Thiết la h&aacute;n</p>\r\n\r\n			<p>S&aacute;t thủ giản</p>\r\n\r\n			<p>Bao dược ho&agrave;n</p>\r\n\r\n			<p>Ph&uacute;c duy&ecirc;n lộ (Trung)</p>\r\n\r\n			<p>B&aacute;ch quả lộ</p>\r\n\r\n			<p>Thi&ecirc;n Sơn Bảo Lộ</p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2><strong>Thưởng Mốc D&atilde; Tẩu:</strong></h2>\r\n\r\n<table align=\"center\" border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:500px\">\r\n	<thead>\r\n		<tr>\r\n			<th scope=\"col\" style=\"text-align:left\">&nbsp; &nbsp;Mốc&nbsp; &nbsp;</th>\r\n			<th scope=\"col\" style=\"text-align:left\">Phần Thưởng</th>\r\n		</tr>\r\n	</thead>\r\n	<tbody>\r\n		<tr>\r\n			<td><strong>100-200-400-600</strong></td>\r\n			<td><strong>Ti&ecirc;n thảo lộ 1h</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>800</strong></td>\r\n			<td><strong>1 Thuỷ Tinh ngẫu nhi&ecirc;n</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>1000</strong></td>\r\n			<td><strong>&nbsp;2 Tinh Hồng Bảo Thạch</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>1200</strong></td>\r\n			<td><strong>Lễ Bao K&iacute; B&iacute;p</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>1500</strong></td>\r\n			<td><strong>Tẩy Tuỷ Kinh</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>2000</strong></td>\r\n			<td><strong>Bảo Rương Hiệp Cốt Nhu T&igrave;nh</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>3000</strong></td>\r\n			<td><strong>Bảo Rương Tr&acirc;n Bảo</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>4000</strong></td>\r\n			<td><strong>Bảo Rương Tr&acirc;n Bảo</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>5000</strong></td>\r\n			<td><strong>Bảo Rương Tr&acirc;n Bảo</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>6000</strong></td>\r\n			<td><strong>Bảo Rương Tr&acirc;n Bảo</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td><strong>8000</strong></td>\r\n			<td><strong>Bảo Rương <span style=\"color:#e74c3c\">HKMP</span></strong></td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<ul>\r\n	<li>\r\n	<p><strong>Bảo rương hiệp cốt như t&igrave;nh: Mở ra nhận ngẫu nhi&ecirc;n 1 vật phẩm <span style=\"color:#16a085\">Hiệp cốt, Như t&igrave;nh</span></strong></p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Bảo Rương Tr&acirc;n Bảo: Mỡ ra ngẫu nhi&ecirc;n nhận được 1 vật phẩm <span style=\"color:#e74c3c\">Hiệp cốt, Như T&igrave;nh, Định Quốc, An Bang</span></strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<div class=\"ddict_btn\" style=\"left:704.859px; top:2289px\"><img src=\"chrome-extension://bpggmmljdiliancllaapiggllnkbjocb/logo/48.png\" /></div>\r\n', '2022-03-20 12:34:40', NULL, 'https://jx1hoiuc.mobi/static/files/uploads/images/600x315.jpg');
INSERT INTO `blog_posts_seo` VALUES (32, '[Hướng Dẫn] Nạp Kim Nguyên Bảo', 'huong-dan-nap-kim-nguyen-bao', NULL, '<p>Th&acirc;n gửi qu&yacute; nh&acirc;n sĩ,<br />\r\nTrong qu&aacute; tr&igrave;nh b&ocirc;n tẩu tại m&aacute;y chủ <span style=\"color:#e74c3c\"><strong>S1 Thi&ecirc;n Sơn T&aacute;i Khởi&nbsp;</strong></span>, qu&yacute; nh&acirc;n sĩ c&oacute; thể Donnate Nhận&nbsp;<strong>Kim Nguy&ecirc;n Bảo</strong>&nbsp;th&ocirc;ng qua c&aacute;c k&ecirc;nh Donnate&nbsp;v&iacute; MOMO&nbsp;hoặc t&agrave;i khoản ng&acirc;n h&agrave;ng. Qu&yacute; nh&acirc;n sĩ c&oacute; thể linh động lựa chọn t&ugrave;y &yacute;.</p>\r\n\r\n<p>Đăng Nhập :&nbsp;http://id.jx1hoiuc.mobi/ - Để Thực Hiện Donnate</p>\r\n\r\n<p>Lưu &yacute;:&nbsp;<strong>c</strong>hỉ duy nhất t&ecirc;n t&agrave;i khoản&nbsp;<strong>Vũ Thị Thanh G</strong>, c&ograve;n lại c&aacute;c t&agrave;i khoản kh&aacute;c đều giả danh.</p>\r\n\r\n<table>\r\n	<tbody>\r\n		<tr>\r\n			<td><strong>Chủ t&agrave;i khoản</strong></td>\r\n			<td><strong>Th&ocirc;ng tin thanh to&aacute;n</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td rowspan=\"3\">&nbsp;\r\n			<p>&nbsp;</p>\r\n\r\n			<p>&nbsp;</p>\r\n			</td>\r\n			<td>\r\n			<p>&nbsp;</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n			<p>&nbsp;</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n			<p>&nbsp;</p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p>&nbsp;</p>\r\n', '2022-03-06 14:56:50', NULL, 'https://jx1hoiuc.mobi/static/files/uploads/images/vltk-thumb.png');

