-- ----------------------------
-- Table structure for blog_sukien
-- ----------------------------
DROP TABLE IF EXISTS `blog_sukien`;
CREATE TABLE `blog_sukien`  (
  `sukienId` int(99) NOT NULL AUTO_INCREMENT,
  `sukienTen` varchar(255) CHARACTER SET utf8 COLLATE utf8_unicode_ci NULL DEFAULT NULL,
  `sukienSlug` varchar(255) CHARACTER SET utf8 COLLATE utf8_unicode_ci NULL DEFAULT NULL,
  `sukienCont` text CHARACTER SET utf8 COLLATE utf8_unicode_ci NULL,
  `sukienImg` varchar(255) CHARACTER SET utf8 COLLATE utf8_unicode_ci NULL DEFAULT NULL,
  `sukienDate` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`sukienId`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8 COLLATE = utf8_unicode_ci ROW_FORMAT = COMPACT;

